// This is a simple interface which specifies echo.Route addition functions which
// are present on both echo.Echo and echo.Group, since we want to allow using
// either of them for path registration
type EchoRouter interface {
	CONNECT(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	DELETE(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	GET(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	HEAD(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	OPTIONS(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	PATCH(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	POST(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	PUT(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	TRACE(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
}

// RegisterHandlers adds each server route to the EchoRouter.
func RegisterHandlers(router EchoRouter, si ServerInterface) {
	RegisterHandlersWithBaseURL(router, si, "")
}

// Registers handlers, and prepends BaseURL to the paths, so that the paths
// can be served under a prefix.
func RegisterHandlersWithBaseURL(router EchoRouter, si ServerInterface, baseURL string) {

	wrapper := ServerInterfaceWrapper{
		Handler: si,
	}

	router.GET(baseURL+"/admin/ping", wrapper.GetAdminPing)
	router.GET(baseURL+"/admin/stats", wrapper.GetAdminStats)
	router.GET(baseURL+"/admin/users", wrapper.GetAdminUsers)
	router.DELETE(baseURL+"/admin/users/:userId/ban", wrapper.UnbanUser)
	router.PUT(baseURL+"/admin/users/:userId/ban", wrapper.BanUser)
	router.PUT(baseURL+"/admin/users/:userId/gender", wrapper.AdminUpdateGender)
	router.PUT(baseURL+"/admin/users/:userId/password", wrapper.AdminUpdatePassword)
	router.PUT(baseURL+"/admin/users/:userId/username", wrapper.AdminUpdateUsername)
	router.POST(baseURL+"/auth/login", wrapper.Login)
	router.POST(baseURL+"/auth/logout", wrapper.Logout)
	router.POST(baseURL+"/auth/refresh", wrapper.RefreshToken)
	router.POST(baseURL+"/auth/register", wrapper.RegisterUser)
	router.GET(baseURL+"/balance", wrapper.GetBalance)
	router.POST(baseURL+"/daily-reward", wrapper.ClaimDailyReward)
	router.GET(baseURL+"/hugs/activity", wrapper.GetHugActivity)
	router.GET(baseURL+"/hugs/cooldown/:userId", wrapper.GetCooldown)
	router.POST(baseURL+"/hugs/cooldown/:userId/upgrade", wrapper.UpgradeCooldown)
	router.GET(baseURL+"/hugs/feed", wrapper.GetHugsFeed)
	router.GET(baseURL+"/hugs/history", wrapper.GetHugHistory)
	router.GET(baseURL+"/hugs/inbox", wrapper.GetHugInbox)
	router.GET(baseURL+"/hugs/inbox/count", wrapper.GetHugInboxCount)
	router.GET(baseURL+"/hugs/outgoing", wrapper.GetOutgoingHug)
	router.POST(baseURL+"/hugs/:hugId/accept", wrapper.AcceptHug)
	router.POST(baseURL+"/hugs/:hugId/cancel", wrapper.CancelHug)
	router.POST(baseURL+"/hugs/:hugId/decline", wrapper.DeclineHug)
	router.POST(baseURL+"/hugs/:userId", wrapper.SuggestHug)
	router.GET(baseURL+"/leaderboard", wrapper.GetLeaderboard)
	router.GET(baseURL+"/ping", wrapper.GetPing)
	router.GET(baseURL+"/users/me", wrapper.GetCurrentUser)
	router.PUT(baseURL+"/users/me/password", wrapper.ChangePassword)
	router.PUT(baseURL+"/users/me/settings", wrapper.UpdateUserSettings)
	router.GET(baseURL+"/users/search", wrapper.SearchUsers)
	router.GET(baseURL+"/users/:userId/profile", wrapper.GetUserProfile)

}

